// THE CONSENT GATE (no AI). Mirrors migration 0020: a member may see the raw
// ORIGINAL photo of a post ONLY when BOTH are true — the member opted in AND the
// admin released that specific post. Both default OFF. The decision is made
// SERVER-SIDE; the client can never set the release flag; and the original is
// delivered only via a short-TTL signed URL (never a column read — source_image_path
// stays REVOKE'd from members).
const i = $json;

// SECURITY: the client must never be able to flip the release. If it tried, that's
// an attack, not a grant — ignore it entirely.
if (i.client_tried_to_set_release) {
  // In the MVP this is structurally impossible (the column is not client-writable);
  // here we make the rule explicit.
}

const memberOptedIn = i.member_photo_consent === true;
const adminReleased  = i.admin_released_this_post === true;   // server-side flag only
const allow = memberOptedIn && adminReleased;                 // AND of two independent gates

return [{ json: {
  post_id: i.post_id,
  member_opted_in: memberOptedIn,
  admin_released: adminReleased,
  client_release_ignored: i.client_tried_to_set_release === true,
  allow_original: allow,
  delivery: allow ? 'short-TTL signed URL to the ORIGINAL' : 'blurred/redacted image only',
  verdict: allow ? 'RELEASE ORIGINAL (both gates open)' : 'WITHHOLD ORIGINAL (a gate is closed)'
}}];
